do $do$
declare
  gid uuid;
  hid uuid;
begin
  select id into gid from public.games where slug='call-of-dragons';
  -- eirlys
  select id into hid from public.heroes where game_id=gid and slug=$hb14$eirlys$hb14$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 0, $hb14$Ranking actual – ¿es Eirlys S-Tier, A-Tier o D-Tier?!$hb14$, $hb14$Mira cómo está rankeada Eirlys en los distintos modos de juego de Call of Dragons en mi tier list actual aquí y además asegúrate de estar usando la mejor facción en Call of Dragons o podrías afectar tu progreso muy negativamente — tengo una guía actualizada sobre las mejores facciones en Call of Dragons aquí

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Gathering, así que las tropas aquí son las tropas de recolección si es que llegas a usarla activamente$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Eirlys$hb14$, $hb14$Emparéjala con lo que tenga sentido para recolectar (gather).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Greenfinger Sickle aumenta muy bien la velocidad de recolección y puede generar un nodo de recolección para ti. Lucias Horn aumenta muy bien la velocidad de recolección y puede generar un nodo de recolección para ti.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Eirlys (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Eirlys con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Eirlys$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Eirlys que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Lo más probable es que la uses en marchas de recolección sin importar lo que digan las habilidades, y este es el mejor árbol de talentos para hacerlo$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2025/09/call-of-dragons-best-flynt-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Eirlys te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-eirlys-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  -- yun-ming
  select id into hid from public.heroes where game_id=gid and slug=$hb14$yun-ming$hb14$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 0, $hb14$Ranking actual – ¿es Yun-Ming S-Tier, A-Tier o D-Tier?!$hb14$, $hb14$Mira cómo está rankeado Yun-Ming en los distintos modos de juego de Call of Dragons en mi tier list actual aquí y además asegúrate de estar usando la mejor facción en Call of Dragons o podrías afectar tu progreso muy negativamente — tengo una guía actualizada sobre las mejores facciones en Call of Dragons aquí

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Él va absolutamente sobre unidades de magic, créeme que son las únicas que querrás usar con él$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Yun-Ming$hb14$, $hb14$Gromara es, como todos los héroes en Call of Dragons que se lanzan juntos, la pareja perfecta (cookies-and-cream) ya que sus kits combinan muy bien juntos (pero hazte un favor y usa a Yun-Ming como primario) (Ver build completo aquí).

Thundelyn es también un héroe que combina muy bien con él gracias a toda la sinergia de su kit y debería ser el héroe a emparejar aquí si no quieres construir a Gromara (Ver build completo aquí).

Thaleia es también una buena opción para usar ya que es muy versátil con héroes de magic (Ver build completo aquí).

Tohar tiene mecánicas básicas similares que también funcionan bien con Yun-Ming (Ver build completo aquí).

Theia es una pareja económica pero que sí funciona ya que Yun-Ming funciona mucho a través de pasivas y no del daño de habilidad activa per se (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Dragons Fate sería en realidad mi segunda opción precisamente por el daño difuso que escalará increíblemente bien a través de Yun-Ming cuando se usa con la war pet Flaming Manticore. Phoenix Eye sería en realidad mi segunda opción precisamente por el daño difuso que escalará increíblemente bien a través de Yun-Ming cuando se usa con la war pet Flaming Manticore.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Yun-Ming (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Yun-Ming con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Yun-Ming$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Yun-Ming que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Este primer árbol de talentos es mi recomendación universal que tiene más sentido para lo que sea que quieras hacer con él. Este árbol está más enfocado a campo abierto (open field) si es eso lo que harás principalmente con él. En mi opinión es genial por la velocidad de marcha sin sacrificar demasiado del resto de sus habilidades solo por la velocidad de marcha$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2025/09/yun-ming-general-talent-tree.jpg$hb14$, $hb14$https://www.allclash.com/wp-content/uploads/2025/09/yun-ming-open-field-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Yun-Ming te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-yun-ming-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
