  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Funciona bien con infantry y se usa mejor con infantry. No está superatado ahí pero recomiendo correrlo con infantry$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-kuma-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Kuma$hb14$, $hb14$Lei Kuan es obviamente la mejor pareja ya que se lanzan juntos y esto es una ley mágica en Call of Dragons: que los héroes que se lanzan el uno con el otro combinan como el tráfico y el clima. La sinergia cruzada aquí, incluso usándola solo para campo abierto, es extremadamente fuerte (Ver build completo aquí).

Skogul con daño de contraataque difuso es también una pareja muy fuerte aquí con él (Ver build completo aquí).

Hosk funciona pero no es el slam dunk malo que podrías pensar, simplemente no son demasiado similares cuando entras en lo profundo de sus habilidades (Ver build completo aquí).

Goresh funciona también pero tampoco es demasiado genial junto a él como los otros héroes listados arriba (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-kuma-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Serpents Edge es una alternativa sólida si todavía no puedes usar su artefacto característico y además funciona bien con él en conjunto. Dragonrift es una alternativa sólida si todavía no puedes usar su artefacto característico y además funciona bien con él en conjunto.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-kuma-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Kuma (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Kuma con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-kuma-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Kuma$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Kuma que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Este es probablemente el build de infantry pura de campo abierto a usar para correrlo en campo abierto. Despiadado, sin nada en lo que comprometerse. Un build de talentos más equilibrado, honestamente, que personalmente me gusta un poco más ya que da un rendimiento general más redondo y de menor mantenimiento$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2025/07/kuma-infantry-pvp-open-field-talent-tree.jpg$hb14$, $hb14$https://www.allclash.com/wp-content/uploads/2025/07/kuma-infantry-support-balanced-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-kuma-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
