  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Debe usarse junto a cavalry$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Lieh-Shan Yen$hb14$, $hb14$Neya está diseñada para él y viceversa y son tan letales juntos que son la mejor pareja que hay el uno con el otro (Ver build completo aquí).

Urag también puede funcionar aunque no sea una pareja tan slam dunk como Neya (Ver build completo aquí).

Emrys es bastante viejo pero con los traits que puede obtener aquí sigue siendo un setup divertido aunque muy lejos del meta (Ver build completo aquí).

Theodore como pareja de garrison funciona pero los pocos jugadores que usan eso probablemente están demasiado ocupados gastando dinero en el juego y no leyendo esto aquí (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Kingslayer también es bueno, especialmente si a tu marcha le falta algo de velocidad de marcha. Springblades también es bueno, especialmente si a tu marcha le falta algo de velocidad de marcha.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Lieh-Shan Yen (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Lieh-Shan Yen con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Lieh-Shan Yen$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Lieh-Shan Yen que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. El árbol de talentos más razonable (asumiendo que no eres una de las 20 ballenas por ahí usándolo como líder de garrison)$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2025/05/call-of-dragons-lieh-shan-yen-best-non-garrison-open-map-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-lieh-shan-yen-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
