  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Absolutamente un comandante de Marksman de pies a cabeza, así que constrúyelo y úsalo exactamente como eso$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-falgrim-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Falgrim$hb14$, $hb14$Sibyl está diseñada para ser su pareja y aunque tienes otras parejas, los dos juntos son la que mejor funciona (Ver build completo aquí).

Kinnara funciona bien con él también ya que él quiere el debuff que ella puede proveer para escalar a través de la pasiva de su 4ª habilidad. Al final no tan arrasador como Sibyl pero una pareja que funciona (Ver build completo aquí).

Mu Hsiang sí combina con todo bien en S3 así que también una pareja viable si te es posible (Ver build completo aquí).

Nico funciona genial con Sibyl pero no tan genial con Falgrim. Tienen el mismo rango pero ambos necesitan debuffs en el objetivo para funcionar así que a menos que tengas otra marcha ahí que aplique muchos debuffs, no son tan geniales juntos (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-falgrim-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
