  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Su habilidad es de rango cuerpo a cuerpo, su habilidad y talentos son de infantry así que sin hacer ningún modelo de theorycraft complicado aquí, infantry es el camino a seguir con Danfel.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Danfel$hb14$, $hb14$Mogro lo que crece junto va junto es algo que los diseñadores de Call of Dragons siempre usan y de nuevo aquí no hay diferencia con los nuevos héroes de infantry funcionando muy bien juntos: Madeline (Ver build completo aquí).

Garwood funciona con Danfel y es de hecho una pareja de legión que me gusta ya que el mayor problema de Danfel no es su kit, es mantenerlo vivo para que pueda usar sus habilidades y Garwood potencia su kit pero también añade bastante supervivencia a eso. Corre a Garwood como comandante principal en esta legión (Ver build completo aquí).

Nika funciona aunque hay dos advertencias aquí. Primero, tienes que correr a Nika como comandante principal de tu legión y segundo, esta es una legión súper ofensiva que hace daño así que necesitas otra legión de infantry cuerpo a cuerpo para tankear o serán eliminadas en cuestión de segundos. Honestamente no recomendaría correrla, pero por completitud aquí, funcionan juntos (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Shield of Sturdiness es ofensivo, tiene grandes stats defensivas y hace daño difuso como su 4ª habilidad y debería ser la mejor opción para ti a menos que tengas el Shield of Sturdiness. Greymars Warhammer es ofensivo, tiene grandes stats defensivas y hace daño difuso como su 4ª habilidad y debería ser la mejor opción para ti a menos que tengas el Shield of Sturdiness.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Danfel (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Danfel con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Danfel$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Danfel que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. No hay demasiado buffeo con él en general y no hay nada demasiado crítico en el árbol de tank, así que prácticamente con todas las parejas donde corras a Danfel como comandante principal querrás usar este build de infantry y obtendrás los mejores resultados y el rendimiento más versátil. Si realmente debes usar un árbol de talentos enfocado en PvP aquí y, por la razón que sea, desprecias el árbol de infantry, puedes potencialmente usar este setup que funcionará increíblemente bien lidiando con otros jugadores en campo abierto.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/09/cod-danfel-infantry-talent-tree.jpg$hb14$, $hb14$https://www.allclash.com/wp-content/uploads/2024/09/cod-danfel-pvp-tank-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-danfel-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
