  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Todo en él es para infantry así que no uses ninguna otra tropa a menos que lo uses en defensa$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Mogro$hb14$, $hb14$Danfel lo que crece junto va junto, ¿cierto? Bueno, en Call of Dragons sí y como se lanzan juntos también hacen la mejor pareja para campo abierto y para garrison. Haces daño de habilidad, escudas, aumentas el daño recibido del objetivo y aplicas debuffs con Danfel que todo juega tan bien a las cartas de Mogro que es inapropiado hasta cierto punto (Ver build completo aquí).

Goresh fuerte héroe de infantry pero más enfocado en el lado defensivo y de daño de contraataque y aunque no hay nada que grite ''no los uses juntos'', simplemente no pegan tan fuerte como podrían con otras parejas (Ver build completo aquí).

Theodore aumenta el daño de habilidad y aunque no parecen una gran combinación al inicio, pueden hacer daño desagradable en general (Ver build completo aquí).

Nika tiene un kit similar pero hay dos cosas que no me gustan demasiado de esta pareja. Una son sus habilidades de peacekeeping, son inútiles aquí y la otra es su reducción de HP de su habilidad activa que no se stackea con la misma que tiene Mogro así que se siente como mucho poder dejado sobre la mesa aquí (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Spiritbone Torc es también muy bueno cuando defiendes tu ciudad con Mogro. Y realísticamente, este es el único caso de uso donde de verdad lo usarías como comandante principal y donde necesitas elegirle un artefacto. Breath of the Forest es también muy bueno cuando defiendes tu ciudad con Mogro. Y realísticamente, este es el único caso de uso donde de verdad lo usarías como comandante principal y donde necesitas elegirle un artefacto.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Mogro (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Mogro con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Mogro$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Mogro que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. La única razón posible por la que correrías a Mogro como comandante principal de tu legión donde su árbol de talentos está activo es cuando lo usas para defender un garrison… y aquí está el árbol de talentos de garrison para eso. Como el árbol de infantry no aporta mucho y el árbol de habilidad tampoco es genial, verás que ir all-in en el árbol de garrison vale la pena, especialmente porque los últimos nodos tienen escaladores de daño plano y reducciones muy poderosos así que no te dejes arrastrar a nada aquí, ve all-in al árbol de garrison con tu Mogro al máximo y tendrás un defensor bastante fuerte y resistente.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/09/mogro-garrison-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Mogro te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-mogro-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  -- urag
  select id into hid from public.heroes where game_id=gid and slug=$hb14$urag$hb14$;
  delete from public.hero_builds where hero_id=hid;
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 0, $hb14$Ranking actual – ¿es Urag S-Tier, A-Tier o D-Tier?!$hb14$, $hb14$Mira cómo está rankeado Urag en los distintos modos de juego de Call of Dragons en mi tier list actual aquí y además asegúrate de estar usando la mejor facción en Call of Dragons o podrías afectar tu progreso muy negativamente — tengo una guía actualizada sobre las mejores facciones en Call of Dragons aquí

¡Importante! No te pierdas Gemas, Llaves, Boosters y Speedups gratis y revisa con frecuencia mi lista de códigos de regalo activos para Call of Dragons aquí.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Aviso completo aquí, como la mayoría de las habilidades en su kit no se preocupan realmente por el tipo de tropa puedes técnicamente armar un setup de infantry muy agresivo con él también, pero en realidad emparejarlo con cavalry simplemente le dará el mayor rendimiento por tu dinero así que quédate con eso en lugar de tratar de hacer funcionar algo que técnicamente puede funcionar pero que por diseño no está realmente pensado para funcionar, especialmente cuando inviertes en él.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Urag$hb14$, $hb14$Tobin es, y esto no es sorpresa, el comandante que mejor combina con Urag, simplemente porque los nuevos héroes que se lanzan juntos en Call of Dragons siempre combinan mejor juntos y sus kits están simplemente diseñados para funcionar de la mano donde realmente obtienes la sostenibilidad para cavalry que Urag necesita ya que todas sus habilidades van prácticamente sobre nukear en campo abierto (Ver build completo aquí).

Alistair así que de hecho antes de juntar dos comandantes legendarios de cavalry aquí -solo porque sí- podrías pensar un poco en Alistair si no lo corres con Tobin ya que dará boost de daño de habilidad por porcentaje y también acumulación de rage que sí se stackea con el kit de Urag y realmente me gusta este setup aunque tienes que enfrentar la realidad de correr no tanto sustain y un comandante épico con él. Aun así, tiene más sentido que cualquier otra pareja legendaria rara con él (Ver build completo aquí).

Emrys funciona con Urag pero aviso completo aquí, serán un glass cannon de daño extremo y te encontrarás en tantas situaciones difíciles que solo recomendaría esta pareja si tienes a tu Emrys bien construido y no planeas construir a Tobin. Nada que recomendaría sin más pero si esa es tu situación esta es una pareja que puede hacer la caza en campo abierto emocionante con la desventaja del peligro constante de que también pueden ser derribados fácilmente si no eliges bien tus batallas (Ver build completo aquí).

Forondil no soy gran fan simplemente porque te estás perdiendo el beneficio de las tropas voladoras aquí (Ver build completo aquí).

Theodore es cavalry pero honestamente no veo mucha sinergia aparte de que ambos son comandantes de cav (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Wolf Howl Horn es una buena opción si lo corres con Alistair ya que esto se activará con la frecuencia suficiente para hacer un aumento de daño consistente. Springblades es una buena opción si lo corres con Alistair ya que esto se activará con la frecuencia suficiente para hacer un aumento de daño consistente.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Urag (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Urag con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Urag$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Urag que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. No demasiados experimentos aquí y este es el árbol de talentos que mejor funciona ya que Urag es realmente directo así que tampoco tienes que ponerte raro con sus talentos.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/07/urag-skill-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Urag te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-urag-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
