  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Con las parejas y todo lo demás, cavalry es la única respuesta válida aquí$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tobin-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Tobin$hb14$, $hb14$Urag sin hacer demasiadas parejas de theorycraft de papel del tipo esto-podría-funcionar, Urag es la única pareja válida que es fuerte y tiene sentido ahora mismo. Emparejados juntos causan estragos sobre tus enemigos, a lo grande, y si no tienes a Urag no construyas a Tobin, así de simple (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tobin-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Los artefactos no son relevantes para Tobin$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tobin-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
