  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Hay dos posibilidades aquí – una es correrla con Maggrat en el garrison donde los tipos de tropa no son tan súper relevantes pero si la sacas fuera de cualquier estructura estacionada querrás archers seguro$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Zayda$hb14$, $hb14$Maggrat debería ser la mayor sorpresa aquí, los nuevos héroes que se lanzan juntos en Call of Dragons siempre combinan excepcionalmente bien juntos y así lo hacen Zayda y Maggrat e incluso superan a Ffraegar con Syndrion como la pareja de mayor daño en el juego ahora (Ver build completo aquí).

Ffraegar con la tasa de crítico mejorada en ataques normales con todos los buffs que Zayda tiene funcionará excepcionalmente bien también si no te apresuras y consigues a Maggrat para correr junto a Zayda (Ver build completo aquí).

Syndrion con Zayda es también una gran pareja ya que sus kits combinan bien juntos (Ver build completo aquí).

Kinnara es probablemente la mejor pareja para jugadores F2P en Call of Dragons y sus kits se complementan muy bien (Ver build completo aquí).

Hosk con la habilidad de awakening puede beneficiarse mucho de ella también y aunque los contraataques no son tan relevantes en esta pareja, funciona bien (Ver build completo aquí).

Kregg puede ser una pareja temprana viable y aunque es un héroe volador, le importan muy poco las unidades voladoras y aún puedes salirte con la tuya con esa pareja (Ver build completo aquí).

Gwanwyn también puede funcionar pero aparte de ser ambos héroes marksman no hay mucha sinergia pero si esa es tu única pareja posible aún la haces (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Gilded Crossbow es el artefacto que quieres elegir si corres a Zayda con Ffraegar y solo con Ffraegar. Goldcrest es el artefacto que quieres elegir si corres a Zayda con Ffraegar y solo con Ffraegar.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Zayda (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Zayda con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Zayda$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Zayda que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Para la mayoría de los jugadores este es el camino a seguir cuando corres a Zayda como comandante principal de tu legión, diseñado para potenciar las stats y daño de los marksmen tanto como sea posible con también alta movilidad. Idealmente quieres emparejarla con Maggrat para esto y entonces puedes hacer asaltos hit-and-run muy efectivos contra mages. Este es el build de talentos de marksman para ella que la hará hacer el daño loco cuando la corres con Syndrion para que pueda rendir con enfoque en eso. Así que, si la construyes para ser tu comandante de legión DPS loca, este es el build de talentos a correr con el enfoque principal en la rama de marksman para conseguir los nodos principales antes de gastar tus puntos en otros lados donde tenga sentido.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/04/call-of-dragons-zayda-talent-tree.jpg$hb14$, $hb14$https://www.allclash.com/wp-content/uploads/2024/04/call-of-dragons-zayda-marksman-talent-build-general-no-syndrion.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Zayda te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-zayda-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  -- maggrat
  select id into hid from public.heroes where game_id=gid and slug=$hb14$maggrat$hb14$;
