  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Bertrand o bien full con unidades de magic junto a Tohar a menos que los uses para defensa, entonces tienes todo el arcoíris de tipos de tropa la mayoría de las veces de todas formas. Pero para todo fuera de defender, solo unidades de magic.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Bertrand$hb14$, $hb14$Tohar es la mejor y obvia pareja ya que es el único héroe de magic que puede proveer el daño de habilidad para activar a Bertrand para crear las marcas que necesita para detonar continuamente. Los dos combinan mejor entre sí (Ver build completo aquí).

Liliya puede funcionar con él y hacer algo de daño pero la forma en que Bertrand generará sus marcas será mucho menor comparada con Tohar y esto debería ser más una pareja de respaldo temporal (Ver build completo aquí).

Velyn es prácticamente igual que Liliya aquí con los kits no encajando perfectamente pero aún así si no tienes a Tohar puedes pensar en emparejar con Velyn y se llevarán bien, solo que no perfectamente (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Mirage Orb funciona con él ya que es un artefacto explosivo sin complicaciones que escala con héroes de magic en Call of Dragons. Infernal Flame funciona con él ya que es un artefacto explosivo sin complicaciones que escala con héroes de magic en Call of Dragons.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Bertrand (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Bertrand con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Bertrand$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Bertrand que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Este es el árbol de talentos ideal cuando usas a Bertrand junto a Tohar para aumentar los efectos de buff y los stacks. Si tienes el talento de season Subjugator, también deberías usar esto con cualquier héroe con el que lo emparejes para el mejor rendimiento. Si lo emparejas con cualquier otro héroe de magic (de hecho también con Tohar funciona) y buscas un build más balanceado y orientado al daño de habilidad que funcione en PvE y PvP, este es el árbol de talentos ideal a usar.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/02/call-of-dragons-bertrand-buff-focused-talent-tree.jpg$hb14$, $hb14$https://www.allclash.com/wp-content/uploads/2024/02/call-of-dragons-bertrand-skill-damage-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Bertrand te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-bertrand-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
