  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Hay dos formas aquí, si sacas a Tohar al mapa obviamente quieres correr unidades de magic pero si lo pones en garrison, pues bien, todos los tipos de tropa están ahí por diseño y lo hacen funcionar igual de bien.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Tohar$hb14$, $hb14$Bertrand es la mejor y obvia pareja ya que así están diseñados los nuevos héroes cuando se lanzan y la razón por la que combinan tan bien juntos es que Tohar ayuda a Bertrand a ganar sus marcas para detonar y son una locura juntos, con Tohar haciendo daño continuo que crea tantas marcas y Bertrand explotando. Campo abierto, fortaleza, lo que quieras, arrasan juntos y absolutamente valen la pena construirlos juntos (Ver build completo aquí).

Liliya puede funcionar con él pero hay algunas palabras de precaución ya que no creo que ninguno de los dos sea bueno en el garrison y en campo abierto dejas mucho sobre la mesa al no usar a Bertrand ya que hay algunas diferencias de daño de área única que hacen que Lily simplemente funcione mejor con un héroe como Velyn (Ver build completo aquí).

Velyn es prácticamente igual que Liliya aquí con los kits no encajando perfectamente pero aún así si no tienes a Bertrand puedes pensar en emparejar con Velyn y se llevarán bien, solo que no perfectamente (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Mirage Orb funciona con él ya que es un artefacto explosivo sin complicaciones que escala con héroes de magic en Call of Dragons. Infernal Flame funciona con él ya que es un artefacto explosivo sin complicaciones que escala con héroes de magic en Call of Dragons.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Tohar (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Tohar con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Tohar$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Tohar que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Usar a Tohar como comandante principal de tu legión significa que lo empareja idealmente con Bertrand u otro héroe de magic que se beneficie de stackear buffs, lo cual este árbol de talentos hace perfectamente.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2024/02/call-of-dragons-tohar-stacking-buffs-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 7, $hb14$Conclusión$hb14$, $hb14$Espero que esta guía para construir a Tohar te haya ayudado a invertir sin perder mucho tiempo ni recursos. Si te gustó o tienes más preguntas (o quizá también anotaciones que crees que deberían añadirse aquí en esta guía), no dudes en publicarlas abajo en la sección de comentarios. Gracias por leer y que tengas un gran día.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-tohar-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
