  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 1, $hb14$Orden de habilidades$hb14$, $hb14$$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 2, $hb14$Mejores tipos de tropa$hb14$, $hb14$Goresh va tanto sobre infantry que quieres correrlo con infantry. Hay algunos experimentos para correrlo con cavalry pero eso es muy específico así que no siento que realmente quieras hacer eso.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 3, $hb14$Mejores parejas de héroe para Goresh$hb14$, $hb14$Skogul como comandante principal funciona muy bien e incluso obtienes el árbol de movilidad para ser mucho más flexible en campo abierto y con el daño de contraataque extra que ella habilita, esta es una pareja perfecta para correr (Ver build completo aquí).

Garwood ayuda mucho a mantener a Goresh vivo y potenciando el contraataque que hace y es también una gran pareja (Ver build completo aquí).

Madeline tiene daño de contraataque lo que combina muy bien con la 3ª habilidad de Goresh pero el escudo puede interponerse aquí también. Se ven geniales en papel pero la realidad es que solo puedes tener un buff de Physical ATK activo así que el buff de Madeline será sobrescrito por el boost de Goresh así que simplemente desaparece (Ver build completo aquí).

Bakhar es, solo mirando el kit, el que funciona prácticamente mejor con él excepto Skogul ya que harás sangrar a tu enemigo una vez que tu salud baje – pero es un comandante épico lo que también te mete en problemas cuando quieres algo fuerte para absorber el daño (Ver build completo aquí).

Hosk mejora las stats y puede ser una buena pareja también buffeándose mutuamente pero no hay mucho en términos de sinergia de contraataque (Ver build completo aquí).

Nika puede funcionar en papel pero tienes un concepto erróneo básico aquí ya que tienes infantry recibiendo daño con Goresh e infantry haciendo daño con Nika lo que lo hace bastante raro en el campo (Ver build completo aquí).$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 4, $hb14$Mejores artefactos$hb14$, $hb14$Ahora echemos un vistazo a los numerosos artefactos que puedes usar. Hemos probado muchos de ellos y algunos tienen una sinergia increíble y otros están más por las stats, pero sin importar qué artefactos tengas disponibles, encontrarás el que funciona mejor. Revisa también la tier list completa de todos los artefactos aquí para ver cuáles valen la inversión en general.

Spiritbone Torc es de hecho un artefacto que me gusta mucho con él ya que ganas DEF y añades daño en el tiempo cuando estás rodeado de legiones enemigas, esto es bueno. Fang of Ashkari es de hecho un artefacto que me gusta mucho con él ya que ganas DEF y añades daño en el tiempo cuando estás rodeado de legiones enemigas, esto es bueno.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 5, $hb14$Mejores sinergias de mascota para Goresh (NUEVO)$hb14$, $hb14$Con el nuevo sistema de war pets en Call of Dragons también es importante emparejar a Goresh con la mascota correcta para ganar más sinergias. Revisa también la tier list completa de todas las war pets en Call of Dragons aquí para ver cuáles valen la inversión en general.$hb14$, '{}'::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
  insert into public.hero_builds (hero_id, order_index, section, content, images, source_url, is_verified) values (hid, 6, $hb14$Mejores builds para Goresh$hb14$, $hb14$A continuación encontrarás los builds de árbol de talentos para Goresh que tienen sentido cuando se usa como comandante principal en cualquier legión en Call of Dragons. Consulta también la descripción debajo de cada árbol de talentos, donde explico una ruta general de cómo deberías gastar tus talentos ahí + algo de contexto adicional para cada build de talentos que muy probablemente agradecerás. Goresh saca el mayor provecho de ir all-in con el árbol de infantry que le ayudará a jugar su kit de contraataque de la mejor manera.$hb14$, array[$hb14$https://www.allclash.com/wp-content/uploads/2023/11/goresh-counterattack-infantry-talent-tree.jpg$hb14$]::text[], $hb14$https://www.allclash.com/best-goresh-builds-talent-skill-order-pairing-pets-in-call-of-dragons/$hb14$, false);
